'use client';

import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer, LineChart, Line, PieChart, Pie, Cell } from 'recharts';

interface AnalyticsClientProps {
    totalShipments: number;
    volumeData: Array<{ date: string, count: number, fullDate: string }>;
    statusData: Array<{ name: string, value: number, fill: string }>;
    locationData: Array<{ name: string, value: number }>;
}

// Custom tooltips and types for Recharts
interface TooltipProps {
    active?: boolean;
    payload?: any[];
    label?: string;
}

const CustomTooltip = ({ active, payload, label }: TooltipProps) => {
    if (active && payload && payload.length) {
        return (
            <div className="bg-brand-surface border border-brand-border/50 p-3 rounded-xl shadow-lg">
                <p className="text-brand-text-muted text-sm mb-1">{label}</p>
                <p className="text-brand-text font-bold">{payload[0].value} Shipments</p>
            </div>
        );
    }
    return null;
};

const PieTooltip = ({ active, payload }: TooltipProps) => {
    if (active && payload && payload.length) {
        const data = payload[0].payload;
        return (
            <div className="bg-brand-surface border border-brand-border/50 p-3 rounded-xl shadow-lg flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: data.fill }} />
                <span className="text-brand-text-muted text-sm">{data.name}:</span>
                <span className="text-brand-text font-bold">{data.value}</span>
            </div>
        );
    }
    return null;
};

export default function AnalyticsClient({ totalShipments, volumeData, statusData, locationData }: AnalyticsClientProps) {

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center mb-6">
                <h1 className="text-2xl font-bold text-brand-text">Analytics Overview</h1>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* Volume Line Chart */}
                <div className="p-6 bg-brand-surface/50 border border-brand-border rounded-2xl lg:col-span-2">
                    <div className="mb-6">
                        <h2 className="text-lg font-semibold text-brand-text">Shipment Volume (Last 30 Days)</h2>
                        <p className="text-sm text-brand-text-muted">Total historical volume: {totalShipments}</p>
                    </div>
                    <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart data={volumeData} margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" stroke="var(--brand-border)" vertical={false} />
                                <XAxis
                                    dataKey="date"
                                    stroke="var(--brand-text-muted)"
                                    fontSize={12}
                                    tickLine={false}
                                    axisLine={false}
                                    minTickGap={30}
                                />
                                <YAxis
                                    stroke="#64748b"
                                    fontSize={12}
                                    tickLine={false}
                                    axisLine={false}
                                    allowDecimals={false}
                                />
                                <RechartsTooltip content={<CustomTooltip />} />
                                <Line
                                    type="monotone"
                                    dataKey="count"
                                    stroke="#3b82f6"
                                    strokeWidth={3}
                                    dot={false}
                                    activeDot={{ r: 6, fill: "#3b82f6", stroke: "var(--bg-main)", strokeWidth: 2 }}
                                />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Status Distribution Donut Chart */}
                <div className="p-6 bg-brand-surface/50 border border-brand-border rounded-2xl">
                    <h2 className="text-lg font-semibold text-brand-text mb-6">Status Distribution</h2>
                    {statusData.length > 0 ? (
                        <div className="h-[300px] w-full relative">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        data={statusData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={80}
                                        outerRadius={110}
                                        paddingAngle={5}
                                        dataKey="value"
                                        stroke="none"
                                    >
                                        {statusData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.fill} />
                                        ))}
                                    </Pie>
                                    <RechartsTooltip content={<PieTooltip />} />
                                </PieChart>
                            </ResponsiveContainer>
                            {/* Inner Text Overlay */}
                            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                                <span className="text-3xl font-bold text-brand-text leading-none">{totalShipments}</span>
                                <span className="text-xs text-brand-text-muted mt-1">Total Shipments</span>
                            </div>
                        </div>
                    ) : (
                        <div className="h-[300px] flex items-center justify-center text-brand-text-muted/80">
                            No active shipments
                        </div>
                    )}
                </div>

                {/* Top Destinations Bar Chart */}
                <div className="p-6 bg-brand-surface/50 border border-brand-border rounded-2xl">
                    <h2 className="text-lg font-semibold text-brand-text mb-6">Top Drop-off Locations</h2>
                    {locationData.length > 0 ? (
                        <div className="h-[300px] w-full mt-4">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={locationData} layout="vertical" margin={{ top: 0, right: 0, bottom: 0, left: 40 }}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="var(--brand-border)" horizontal={false} />
                                    <XAxis type="number" stroke="var(--brand-text-muted)" fontSize={12} tickLine={false} axisLine={false} allowDecimals={false} />
                                    <YAxis dataKey="name" type="category" stroke="var(--brand-text-muted)" fontSize={11} tickLine={false} axisLine={false} width={80} />
                                    <RechartsTooltip cursor={{ fill: 'var(--bg-surface)' }} content={<CustomTooltip />} />
                                    <Bar dataKey="value" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={24} />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    ) : (
                        <div className="h-[300px] flex items-center justify-center text-brand-text-muted/80">
                            No location data available
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
}

import prisma from "@/lib/prisma"
import { getServerSession } from "next-auth"
import { authOptions } from "@/lib/auth"
import AnalyticsClient from "./components/AnalyticsClient"

export default async function AnalyticsPage({ searchParams }: { searchParams: Promise<{ viewAs?: string }> }) {
    const session = await getServerSession(authOptions)
    if (!session) return null

    const { viewAs } = await searchParams;
    let targetUserId: string | null = session.user.id;

    if (session.user.role === 'SUPER_ADMIN') {
        if (viewAs) {
            targetUserId = viewAs;
        } else {
            targetUserId = null;
        }
    }

    const whereClause: any = { isDeleted: false };
    if (targetUserId) {
        whereClause.adminId = targetUserId;
    }

    // Fetch all relevant shipments
    const shipments = await prisma.shipment.findMany({
        where: whereClause,
        select: {
            id: true,
            status: true,
            createdAt: true,
            origin: true,
            destination: true,
        }
    });

    // --- Data Aggregation ---

    // 1. Volume over time (Last 30 days)
    const last30Days = [...Array(30)].map((_, i) => {
        const d = new Date();
        d.setDate(d.getDate() - i);
        return d.toISOString().split('T')[0];
    }).reverse();

    const volumeData = last30Days.map(dateStr => {
        const count = shipments.filter(s => {
            const sDate = new Date(s.createdAt).toISOString().split('T')[0];
            return sDate === dateStr;
        }).length;

        // Format for display (e.g. Feb 21)
        const d = new Date(dateStr);
        const displayDate = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

        return { date: displayDate, count, fullDate: dateStr };
    });

    // 2. Status Distribution
    const statusCounts = shipments.reduce((acc, curr) => {
        acc[curr.status] = (acc[curr.status] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    // Map to recharts format and include safe UI colors
    const COLORS: Record<string, string> = {
        'DELIVERED': '#22c55e', // text-green-500
        'CREATED': '#eab308',   // text-yellow-500
        'PENDING': '#eab308',
        'ON_HOLD': '#f97316',   // text-orange-500
        'RETURNED': '#ef4444',  // text-red-500
        'OUT_FOR_DELIVERY': '#a855f7', // text-purple-500
        'IN_TRANSIT': '#3b82f6', // text-blue-500
    };

    const statusData = Object.entries(statusCounts).map(([name, value]) => ({
        name: name.replace(/_/g, ' '),
        value,
        fill: COLORS[name] || '#64748b' // fallback slate
    }));

    // 3. Top Locations (Destinations)
    const destinationCounts = shipments.reduce((acc, curr) => {
        const dest = curr.destination || 'Unknown';
        acc[dest] = (acc[dest] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    const locationData = Object.entries(destinationCounts)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 5); // top 5

    return (
        <div className="space-y-6">
            {session.user.role === 'SUPER_ADMIN' && viewAs && (
                <div className="bg-purple-500/10 border border-purple-500/20 text-purple-400 px-4 py-3 rounded-xl mb-6 flex items-center">
                    <span className="font-semibold mr-2">Analytics for Admin:</span> {targetUserId}
                </div>
            )}
            {session.user.role === 'SUPER_ADMIN' && !viewAs && (
                <div className="bg-blue-500/10 border border-blue-500/20 text-blue-400 px-4 py-3 rounded-xl mb-6 flex items-center">
                    <span className="font-semibold mr-2">System Wide Analytics:</span> Viewing all shipments across all admins.
                </div>
            )}

            <AnalyticsClient
                volumeData={volumeData}
                statusData={statusData}
                locationData={locationData}
                totalShipments={shipments.length}
            />
        </div>
    )
}

import prisma from "@/lib/prisma";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { redirect } from "next/navigation";
import { ScrollText } from "lucide-react";

export const dynamic = 'force-dynamic';

export default async function AuditLogsPage() {
    const session = await getServerSession(authOptions);
    if (!session) redirect('/login');
    if (session.user.role !== 'SUPER_ADMIN') {
        return (
            <div className="p-8 text-center text-red-500">
                Unauthorized: Only Super Admins can view audit logs.
            </div>
        );
    }

    const logs = await prisma.auditLog.findMany({
        orderBy: { createdAt: 'desc' },
        take: 100,
        include: {
            admin: {
                select: { name: true, email: true }
            }
        }
    });

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold text-brand-text mb-2">Audit Logs</h1>
                <p className="text-brand-text-muted">View recent system actions and security events.</p>
            </div>

            <div className="bg-brand-surface border border-brand-border rounded-2xl overflow-hidden shadow-xl">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-brand-bg/50 border-b border-brand-border/50 text-brand-text-muted">
                                <th className="p-4 font-semibold">Time</th>
                                <th className="p-4 font-semibold">Admin</th>
                                <th className="p-4 font-semibold">Action</th>
                                <th className="p-4 font-semibold">Entity ID</th>
                                <th className="p-4 font-semibold">Details</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-brand-border text-brand-text-muted text-sm">
                            {logs.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="p-8 text-center text-brand-text-muted/80">
                                        No logs found.
                                    </td>
                                </tr>
                            ) : (
                                logs.map((log) => (
                                    <tr key={log.id} className="hover:bg-brand-bg transition-colors">
                                        <td className="p-4 whitespace-nowrap">
                                            {new Date(log.createdAt).toLocaleString()}
                                        </td>
                                        <td className="p-4 text-brand-text">
                                            {log.admin.name || log.admin.email}
                                        </td>
                                        <td className="p-4">
                                            <span className={`inline-block px-2 py-1 rounded text-xs font-semibold
                                                ${log.action.includes('DELETE') ? 'bg-red-500/10 text-red-400 border border-red-500/20' :
                                                    log.action.includes('CREATE') ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' :
                                                        'bg-blue-500/10 text-blue-400 border border-blue-500/20'
                                                }`}>
                                                {log.action}
                                            </span>
                                        </td>
                                        <td className="p-4 font-mono text-xs text-brand-text-muted/80">
                                            {log.entityId}
                                        </td>
                                        <td className="p-4 max-w-xs truncate" title={log.details || ''}>
                                            {log.details}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import prisma from "@/lib/prisma"
import { getServerSession } from "next-auth"
import { authOptions } from "@/lib/auth"
import { Package, Truck, CheckCircle, Clock } from "lucide-react"

async function getStats(userId: string | null) {
    const where: any = { isDeleted: false };
    if (userId) {
        where.adminId = userId;
    }

    const [total, pending, inTransit, delivered] = await Promise.all([
        prisma.shipment.count({ where }),
        prisma.shipment.count({ where: { ...where, status: { in: ["CREATED", "PENDING"] } } }),
        prisma.shipment.count({ where: { ...where, status: "IN_TRANSIT" } }),
        prisma.shipment.count({ where: { ...where, status: "DELIVERED" } })
    ]);
    return { total, pending, inTransit, delivered };
}

export default async function DashboardPage({ searchParams }: { searchParams: Promise<{ viewAs?: string }> }) {
    const session = await getServerSession(authOptions);
    if (!session) return null;

    const { viewAs } = await searchParams;
    let targetUserId: string | null = session.user.id; // Default to self

    if (session.user.role === 'SUPER_ADMIN') {
        if (viewAs) {
            targetUserId = viewAs; // View as specific admin
        } else {
            targetUserId = null; // View ALL shipments system-wide
        }
    }

    const stats = await getStats(targetUserId);

    const statCards = [
        { label: "Total Shipments", value: stats.total, icon: Package, color: "text-blue-400", bg: "bg-blue-500/10", border: "border-blue-500/20" },
        { label: "Pending", value: stats.pending, icon: Clock, color: "text-yellow-400", bg: "bg-yellow-500/10", border: "border-yellow-500/20" },
        { label: "In Transit", value: stats.inTransit, icon: Truck, color: "text-purple-400", bg: "bg-purple-500/10", border: "border-purple-500/20" },
        { label: "Delivered", value: stats.delivered, icon: CheckCircle, color: "text-green-400", bg: "bg-green-500/10", border: "border-green-500/20" },
    ];

    // Recent Inquiries (Unread)
    // Super Admin sees ALL unread messages. Regular Admins only see their own.
    const unreadWhere: any = {
        isDeleted: false,
        messages: {
            some: {
                sender: 'CLIENT',
                isRead: false
            }
        }
    };

    if (targetUserId) {
        unreadWhere.adminId = targetUserId;
    }

    const unreadShipments: any[] = await prisma.shipment.findMany({
        where: unreadWhere,
        include: {
            messages: {
                where: { sender: 'CLIENT', isRead: false },
                select: { id: true, createdAt: true, content: true },
                orderBy: { createdAt: 'desc' },
                take: 1
            }
        } as any
    });

    return (
        <div className="space-y-6">
            {session.user.role === 'SUPER_ADMIN' && viewAs && (
                <div className="bg-purple-500/10 border border-purple-500/20 text-purple-400 px-4 py-3 rounded-xl mb-6 flex items-center">
                    <span className="font-semibold mr-2">Viewing as Admin:</span> {targetUserId}
                </div>
            )}
            {session.user.role === 'SUPER_ADMIN' && !viewAs && (
                <div className="bg-blue-500/10 border border-blue-500/20 text-blue-400 px-4 py-3 rounded-xl mb-6 flex items-center">
                    <span className="font-semibold mr-2">System Wide Overview:</span> Viewing all shipments across all admins.
                </div>
            )}
            <h1 className="text-2xl font-bold text-brand-text mb-6">Dashboard Overview</h1>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {statCards.map((stat) => (
                    <div key={stat.label} className={`p-6 rounded-2xl border ${stat.border} ${stat.bg} backdrop-blur-sm`}>
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-brand-text-muted text-sm font-medium">{stat.label}</p>
                                <p className="text-3xl font-bold text-brand-text mt-1">{stat.value}</p>
                            </div>
                            <div className={`p-3 rounded-xl ${stat.bg} ${stat.color} border ${stat.border}`}>
                                <stat.icon className="w-6 h-6" />
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mt-8">
                {/* Quick Actions */}
                <div className="lg:col-span-2 p-6 bg-brand-surface/50 border border-brand-border rounded-2xl">
                    <h2 className="text-lg font-semibold text-brand-text mb-4">Quick Actions</h2>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <a href="/admin/shipments" className="hover:no-underline block p-4 border border-blue-500/20 bg-blue-500/10 hover:bg-blue-500/20 rounded-xl transition-colors">
                            <h3 className="font-semibold text-blue-400 mb-1">Manage Shipments</h3>
                            <p className="text-brand-text-muted text-xs text-sm">View and update all shipments</p>
                        </a>
                        <a href="/admin/settings" className="hover:no-underline block p-4 border border-emerald-500/20 bg-emerald-500/10 hover:bg-emerald-500/20 rounded-xl transition-colors">
                            <h3 className="font-semibold text-emerald-400 mb-1">Platform Settings</h3>
                            <p className="text-brand-text-muted text-xs">Manage your brand logo and details</p>
                        </a>
                        {session.user.role === 'SUPER_ADMIN' && (
                            <a href="/admin/users" className="hover:no-underline block p-4 border border-purple-500/20 bg-purple-500/10 hover:bg-purple-500/20 rounded-xl transition-colors">
                                <h3 className="font-semibold text-purple-400 mb-1">Manage Admins</h3>
                                <p className="text-brand-text-muted text-xs">Create and modify admin accounts</p>
                            </a>
                        )}
                    </div>
                </div>

                {/* Recent Inquiries */}
                <div className="p-6 bg-brand-surface/50 border border-brand-border rounded-2xl">
                    <h2 className="text-lg font-semibold text-brand-text mb-4 flex items-center gap-2">
                        Recent Inquiries
                        {unreadShipments.length > 0 && (
                            <span className="bg-red-500 text-white text-xs px-2 py-0.5 rounded-full">{unreadShipments.length}</span>
                        )}
                    </h2>
                    <div className="space-y-3">
                        {unreadShipments.length === 0 ? (
                            <p className="text-brand-text-muted/80 text-sm">No new messages.</p>
                        ) : (
                            unreadShipments.map(shipment => (
                                <a
                                    key={shipment.id}
                                    href={`/admin/shipments/${shipment.id}`}
                                    className="block p-3 rounded-xl bg-brand-surface border border-brand-border/50 hover:border-blue-500/50 transition-colors"
                                >
                                    <div className="flex justify-between items-start mb-1">
                                        <span className="font-mono text-blue-400 font-semibold">{shipment.trackingNumber}</span>
                                        <span className="text-xs text-brand-text-muted/80" suppressHydrationWarning>
                                            {shipment.messages[0] ? new Date(shipment.messages[0].createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                                        </span>
                                    </div>
                                    <p className="text-brand-text-muted text-sm truncate">
                                        {shipment.messages[0]?.content || 'New message'}
                                    </p>
                                </a>
                            ))
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Search, MapPin, Calendar, ArrowRight, RefreshCcw, Trash2 } from 'lucide-react';
import { toast } from 'react-hot-toast';
import FormattedDate from "@/components/FormattedDate";

export default function RecycleBinClient({ initialShipments }: { initialShipments: any[] }) {
    const router = useRouter();
    const [searchTerm, setSearchTerm] = useState('');

    const filteredShipments = initialShipments.filter(shipment => {
        return shipment.trackingNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
            shipment.receiverInfo.toLowerCase().includes(searchTerm.toLowerCase());
    });

    const handleRestore = async (id: string) => {
        try {
            const res = await fetch(`/api/shipments/${id}/restore`, { method: 'PATCH' });
            if (res.ok) {
                toast.success('Shipment restored');
                router.refresh();
            } else {
                toast.error('Failed to restore shipment');
            }
        } catch (e) {
            console.error(e);
            toast.error('Error restoring shipment');
        }
    };

    const handleForceDelete = async (id: string) => {
        if (!confirm('WARNING: This will permanently delete the shipment and all its data. This cannot be undone. Area you sure?')) return;
        try {
            const res = await fetch(`/api/shipments/${id}/force-delete`, { method: 'DELETE' });
            if (res.ok) {
                toast.success('Shipment permanently deleted');
                router.refresh();
            } else {
                toast.error('Failed to permanently delete shipment');
            }
        } catch (e) {
            console.error(e);
            toast.error('Error permanently deleting shipment');
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex gap-4 mb-6">
                <div className="relative flex-1 max-w-md">
                    <Search className="absolute left-4 top-3.5 w-5 h-5 text-brand-text-muted/80" />
                    <input
                        type="text"
                        placeholder="Search deleted shipments..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-brand-surface border border-brand-border text-brand-text placeholder-brand-text-muted/50 rounded-xl py-3 pl-12 pr-4 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                    />
                </div>
            </div>

            <div className="bg-brand-surface border border-brand-border rounded-2xl overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-brand-bg/50 text-brand-text-muted text-sm font-medium">
                            <tr>
                                <th className="px-6 py-4">Tracking ID</th>
                                <th className="px-6 py-4">Route</th>
                                <th className="px-6 py-4">Deleted At</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-brand-border">
                            {filteredShipments.map((shipment) => (
                                <tr key={shipment.id} className="hover:bg-brand-bg transition-colors group opacity-75 hover:opacity-100">
                                    <td className="px-6 py-4">
                                        <span className="font-mono text-brand-text-muted font-medium line-through decoration-brand-text-muted/50">{shipment.trackingNumber}</span>
                                        <div className="text-brand-text-muted/50 text-xs mt-1">{shipment.receiverInfo}</div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center text-brand-text-muted/80 text-sm">
                                            <span className="max-w-[100px] truncate">{shipment.origin}</span>
                                            <ArrowRight className="w-3 h-3 mx-2 text-brand-text-muted/50" />
                                            <span className="max-w-[100px] truncate">{shipment.destination}</span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-brand-text-muted/80 text-sm">
                                        {shipment.deletedAt ? <FormattedDate date={shipment.deletedAt} /> : 'Unknown'}
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center justify-end gap-3">
                                            <button
                                                onClick={() => handleRestore(shipment.id)}
                                                className="flex items-center px-3 py-1.5 bg-blue-500/10 text-blue-400 hover:bg-blue-600 hover:text-white rounded-lg transition-colors text-sm font-medium"
                                                title="Restore Shipment"
                                            >
                                                <RefreshCcw className="w-4 h-4 mr-1.5" />
                                                Restore
                                            </button>
                                            <button
                                                onClick={() => handleForceDelete(shipment.id)}
                                                className="flex items-center px-3 py-1.5 bg-red-500/10 text-red-500 hover:bg-red-600 hover:text-white rounded-lg transition-colors text-sm font-medium"
                                                title="Permanently Delete"
                                            >
                                                <Trash2 className="w-4 h-4 mr-1.5" />
                                                Delete
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                    {filteredShipments.length === 0 && (
                        <div className="p-12 border-t border-brand-border text-center flex flex-col items-center justify-center space-y-3">
                            <Trash2 className="w-12 h-12 text-brand-text-muted/30" />
                            <p className="text-brand-text-muted/80 font-medium">Recycle bin is empty.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import prisma from "@/lib/prisma"
import { getServerSession } from "next-auth"
import { authOptions } from "@/lib/auth"
import RecycleBinClient from "./components/RecycleBinClient"

export default async function RecycleBinPage({ searchParams }: { searchParams: Promise<{ viewAs?: string }> }) {
    const session = await getServerSession(authOptions)
    if (!session) return null

    const { viewAs } = await searchParams;
    let targetUserId: string | null = session.user.id;

    if (session.user.role === 'SUPER_ADMIN') {
        if (viewAs) {
            targetUserId = viewAs;
        } else {
            targetUserId = null; // null means 'fetch everything'
        }
    }

    const whereClause: any = { isDeleted: true };
    if (targetUserId) {
        whereClause.adminId = targetUserId;
    }

    // Fetch ONLY deleted shipments
    const deletedShipments = await prisma.shipment.findMany({
        where: whereClause,
        orderBy: { deletedAt: 'desc' },
        include: {
            events: {
                orderBy: { timestamp: 'desc' },
                take: 1
            }
        }
    })

    return (
        <div>
            {targetUserId && targetUserId !== session.user.id && (
                <div className="bg-purple-500/10 border border-purple-500/20 text-purple-400 px-4 py-3 rounded-xl mb-6 flex items-center">
                    <span className="font-semibold mr-2">Viewing Recycle Bin for Admin:</span> {targetUserId}
                </div>
            )}
            {!targetUserId && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-3 rounded-xl mb-6 flex items-center">
                    <span className="font-semibold mr-2">System Wide Recycle Bin:</span> Viewing all deleted shipments across all admins.
                </div>
            )}

            <div className="mb-6">
                <h1 className="text-2xl font-bold text-white mb-2">Recycle Bin</h1>
                <p className="text-brand-text-muted text-sm">Shipments that have been deleted. You can restore them or permanently delete them here.</p>
            </div>

            <RecycleBinClient initialShipments={deletedShipments} />
        </div>
    )
}

'use client';

import { useState, useEffect } from 'react';
import { Building2, Mail, Phone, Upload, Loader2, Save, Moon, Sun } from 'lucide-react';
import { toast } from 'react-hot-toast';
import { useTheme } from '@/components/ThemeProvider';

export default function SettingsDashboard() {
    const { theme, setTheme } = useTheme();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    const [settings, setSettings] = useState({
        companyName: '',
        supportEmail: '',
        supportPhone: '',
        logoUrl: '',
        theme: 'dark' as 'dark' | 'light'
    });

    useEffect(() => {
        fetch('/api/settings')
            .then(res => res.json())
            .then(data => {
                if (data) {
                    setSettings({
                        companyName: data.companyName || '',
                        supportEmail: data.supportEmail || '',
                        supportPhone: data.supportPhone || '',
                        logoUrl: data.logoUrl || '',
                        theme: data.theme || 'dark'
                    });
                    // Also update global theme if different
                    if (data.theme && data.theme !== theme) {
                        setTheme(data.theme);
                    }
                }
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                toast.error('Failed to load settings');
                setLoading(false);
            });
