'use client';

import { useState, useEffect, useRef } from 'react';
import { Send, MessageCircle, RefreshCw, Trash2, Edit2, X, Check, Paperclip } from 'lucide-react';

interface Message {
    id: string;
    content: string;
    imageUrl?: string | null;
    sender: 'CLIENT' | 'ADMIN';
    createdAt: string;
}

export default function ShipmentChat({ shipmentId }: { shipmentId: string }) {
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [sending, setSending] = useState(false);
    const [uploadingImage, setUploadingImage] = useState(false);
    const [editingMessageId, setEditingMessageId] = useState<string | null>(null);
    const [editingContent, setEditingContent] = useState('');
    const fileInputRef = useRef<HTMLInputElement>(null);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        fetchMessages();
        const interval = setInterval(fetchMessages, 5000);
        return () => clearInterval(interval);
    }, [shipmentId]);

    useEffect(() => {
        if (scrollRef.current && !editingMessageId) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages.length, editingMessageId]);

    const fetchMessages = async () => {
        try {
            const res = await fetch(`/api/shipments/${shipmentId}/messages`);
            if (res.ok) {
                const data = await res.json();
                setMessages(data);

                // Mark as read if latest message is from client
                if (data.length > 0) {
                    markAsRead();
                }
            }
        } catch (e) {
            console.error(e);
        }
    };

    const markAsRead = async () => {
        try {
            await fetch(`/api/shipments/${shipmentId}/messages/read`, { method: 'POST' });
        } catch (e) {
            console.error('Failed to mark read', e);
        }
    }

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setUploadingImage(true);
        try {
            const formData = new FormData();
            formData.append('file', file);

            const uploadRes = await fetch(`/api/upload/public?filename=${encodeURIComponent(file.name)}`, {
                method: 'POST',
                body: file,
            });

            if (uploadRes.ok) {
                const blob = await uploadRes.json();

                await fetch(`/api/shipments/${shipmentId}/messages`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        content: '',
                        imageUrl: blob.url,
                        sender: 'ADMIN'
                    })
                });
                fetchMessages();
            }
        } catch (error) {
            console.error('Image upload failed', error);
        } finally {
            setUploadingImage(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMessage.trim()) return;

        setSending(true);
        try {
            const res = await fetch(`/api/shipments/${shipmentId}/messages`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    content: newMessage,
                    sender: 'ADMIN'
                })
            });

            if (res.ok) {
                setNewMessage('');
                fetchMessages();
            }
        } catch (e) {
            console.error(e);
        } finally {
            setSending(false);
        }
    };

    const handleDeleteMessage = async (messageId: string) => {
        if (!confirm('Are you sure you want to delete this message? This cannot be undone.')) return;
        try {
            const res = await fetch(`/api/messages/${messageId}`, { method: 'DELETE' });
            if (res.ok) {
                setMessages(prev => prev.filter(m => m.id !== messageId));
            }
        } catch (e) {
            console.error('Failed to delete message:', e);
        }
    };

    const handleSaveEdit = async (messageId: string) => {
        if (!editingContent.trim()) return;
        try {
            const res = await fetch(`/api/messages/${messageId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content: editingContent })
            });
            if (res.ok) {
                setMessages(prev => prev.map(m => m.id === messageId ? { ...m, content: editingContent } : m));
                setEditingMessageId(null);
                setEditingContent('');
            }
        } catch (e) {
            console.error('Failed to update message:', e);
        }
    };

    return (
        <div className="bg-brand-surface border border-brand-border rounded-2xl flex flex-col h-[600px] max-h-[calc(100vh-120px)] overflow-hidden w-full">
            <div className="p-4 border-b border-brand-border flex justify-between items-center bg-brand-surface/50">
                <h3 className="font-bold text-brand-text flex items-center gap-2">
                    <MessageCircle className="w-5 h-5 text-blue-400" />
                    Customer Inquiries
                </h3>
                <button onClick={fetchMessages} className="text-brand-text-muted hover:text-brand-text" title="Refresh">
                    <RefreshCw className="w-4 h-4" />
                </button>
            </div>

            <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 bg-brand-bg/30">
                {messages.length === 0 ? (
                    <div className="text-center text-brand-text-muted text-sm mt-20">
                        No messages yet.
                    </div>
                ) : (
                    messages.map((msg) => (
                        <div
                            key={msg.id}
                            className={`flex ${msg.sender === 'ADMIN' ? 'justify-end' : 'justify-start'} group w-full`}
                        >
                            {msg.sender === 'ADMIN' && editingMessageId !== msg.id && (
                                <div className="flex flex-col justify-center sm:flex-row items-center gap-1 opacity-100 sm:opacity-0 group-hover:opacity-100 transition-opacity mr-2">
                                    <button
                                        onClick={() => { setEditingMessageId(msg.id); setEditingContent(msg.content || ''); }}
                                        className="text-brand-text-muted hover:text-blue-400 p-1.5 rounded-lg hover:bg-brand-bg transition-colors"
                                        title="Edit message"
                                    >
                                        <Edit2 className="w-4 h-4" />
                                    </button>
                                    <button
                                        onClick={() => handleDeleteMessage(msg.id)}
                                        className="text-brand-text-muted hover:text-red-400 p-1.5 rounded-lg hover:bg-brand-bg transition-colors"
                                        title="Delete message"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            )}

                            <div className="max-w-[80%]">
                                {editingMessageId === msg.id ? (
                                    <div className="bg-brand-surface p-3 rounded-2xl border border-brand-border flex flex-col gap-2 w-full shadow-lg">
                                        <textarea
                                            value={editingContent}
                                            onChange={(e) => setEditingContent(e.target.value)}
                                            className="w-full bg-brand-bg border border-brand-border rounded-xl px-3 py-2 text-brand-text text-sm focus:outline-none focus:border-blue-500 resize-none"
                                            rows={3}
                                            autoFocus
                                            spellCheck={false}
                                        />
                                        <div className="flex justify-end gap-2">
                                            <button
                                                onClick={() => setEditingMessageId(null)}
                                                className="text-slate-400 hover:text-white px-2 py-1 text-xs font-medium rounded-md hover:bg-slate-700 transition-colors"
                                            >
                                                Cancel
                                            </button>
                                            <button
                                                onClick={() => handleSaveEdit(msg.id)}
                                                disabled={!editingContent.trim()}
                                                className="bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white px-3 py-1 text-xs font-bold rounded-md transition-colors flex items-center gap-1"
                                            >
                                                Save
                                            </button>
                                        </div>
                                    </div>
                                ) : (
                                    <div
                                        className={`rounded-2xl px-4 py-3 text-sm flex flex-col break-words min-w-0 ${msg.sender === 'ADMIN'
                                            ? 'bg-blue-600 text-white rounded-tr-none'
                                            : 'bg-brand-surface text-brand-text rounded-tl-none border border-brand-border'
                                            }`}
                                    >
                                        {msg.imageUrl && (
                                            // eslint-disable-next-line @next/next/no-img-element
                                            <img src={msg.imageUrl} alt="Attachment" className="max-w-full rounded-xl mb-2 border border-blue-500/50" />
                                        )}
                                        {msg.content && <p className="whitespace-pre-wrap">{msg.content}</p>}
                                    </div>
                                )}
                                <p className={`text-[10px] mt-1 px-1 ${msg.sender === 'ADMIN' ? 'text-right text-slate-500' : 'text-slate-500'
                                    }`}>
                                    <span suppressHydrationWarning>
                                        {new Date(msg.createdAt).toLocaleString(undefined, {
                                            month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
                                        })}
                                    </span>
                                </p>
                            </div>
                        </div>
                    ))
                )}
            </div>

            <form onSubmit={handleSend} className="p-4 border-t border-brand-border bg-brand-surface shrink-0">
                <div className="flex gap-2 items-center w-full min-w-0">
                    <input
                        type="file"
                        accept="image/*"
                        className="hidden"
                        ref={fileInputRef}
                        onChange={handleImageUpload}
                    />
                    <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        disabled={sending || uploadingImage}
                        className="p-2.5 text-brand-text-muted hover:text-brand-text bg-brand-bg border border-brand-border hover:border-brand-border/50 rounded-xl transition-colors disabled:opacity-50"
                        title="Attach Picture"
                    >
                        {uploadingImage ? <RefreshCw className="w-5 h-5 animate-spin" /> : <Paperclip className="w-5 h-5 shrink-0" />}
                    </button>
                    <input
                        type="text"
                        value={newMessage}
                        onChange={e => setNewMessage(e.target.value)}
                        placeholder="Type a message..."
                        className="flex-1 min-w-0 bg-brand-bg border border-brand-border rounded-xl px-4 py-2.5 text-brand-text focus:outline-none focus:border-blue-500 transition-colors placeholder:text-brand-text-muted/50"
                    />
                    <button
                        type="submit"
                        disabled={sending || uploadingImage || !newMessage.trim()}
                        className="bg-blue-600 hover:bg-blue-500 text-white p-2.5 rounded-xl disabled:opacity-50 transition-colors shrink-0"
                    >
                        <Send className="w-5 h-5" />
                    </button>
                </div>
            </form>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { ArrowLeft, Printer, MapPin, Loader2, CheckCircle2, Clock, Pencil, X, Check, FileText, Trash2, Mail } from 'lucide-react';
import { toast } from 'react-hot-toast';
import dynamic from 'next/dynamic';
import ShippingLabelPDF from '@/components/pdf/ShippingLabelPDF';
import ShipmentChat from './ShipmentChat';
import FormattedDate from '@/components/FormattedDate';
import { parseShipmentInfo } from '@/lib/utils';

const PDFDownloadLink = dynamic(
    () => import('@react-pdf/renderer').then((mod) => mod.PDFDownloadLink),
    {
        ssr: false,
        loading: () => <button className="flex items-center px-4 py-2 bg-blue-600/50 text-white rounded-xl">Loading...</button>,
    }
);

export default function ShipmentDetailsClient({ shipment, settings }: { shipment: any, settings?: any }) {
    const router = useRouter();
    const [updating, setUpdating] = useState(false);
    const [formData, setFormData] = useState({
        status: 'PENDING',
        location: '',
        description: '',
        latitude: '',
        longitude: '',
        timestamp: ''
    });

    useEffect(() => {
        setFormData(prev => ({ ...prev, timestamp: new Date().toISOString().slice(0, 16) }));
    }, []);

    const [sendingEmailId, setSendingEmailId] = useState<string | null>(null);

    const handleResendEmail = async (eventId: string) => {
        setSendingEmailId(eventId);
        try {
            const res = await fetch(`/api/shipments/${shipment.id}/event/${eventId}/resend`, {
                method: 'POST'
            });

            if (res.ok) {
                toast.success("Email resent successfully");
            } else {
                const error = await res.text();
                toast.error(error || "Failed to resend email");
            }
        } catch (e) {
            console.error(e);
            toast.error("Error resending email");
        } finally {
            setSendingEmailId(null);
        }
    };
    const actuallyDeleteEvent = async (eventId: string) => {
        try {
            const res = await fetch(`/api/shipments/${shipment.id}/event/${eventId}`, { method: 'DELETE' });
            if (res.ok) {
                toast.dismiss(); // Clear all toasts
                toast.success('Event deleted', { duration: 3000 });
                router.refresh();
            } else {
                toast.dismiss(); 
                const errorText = await res.text();
                toast.error(`Failed to delete: ${errorText || res.statusText}`, { duration: 5000 });
            }
        } catch (e) {
            console.error(e);
            toast.error('Error deleting event');
        }
    };

    const handleDeleteEvent = (eventId: string) => {
        toast.dismiss(); // Prevent stacking multiple dialogs
        toast((t) => (
            <div className="flex flex-col gap-3 p-1">
                <p className="font-semibold text-sm">Delete this tracking event?</p>
                <div className="flex gap-2 justify-end">
                    <button 
                        onClick={() => toast.dismiss(t.id)}
                        className="px-3 py-1.5 text-xs font-medium text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={() => {
                            toast.dismiss(t.id);
                            actuallyDeleteEvent(eventId);
                        }}
                        className="px-3 py-1.5 text-xs font-medium bg-red-600 text-white hover:bg-red-500 rounded-lg transition-colors shadow-sm"
                    >
                        Confirm Delete
                    </button>
                </div>
            </div>
        ), {
            duration: Infinity, // Keep confirmation visible until action
            position: 'top-center',
            style: {
                background: '#ffffff',
                color: '#1e293b',
                padding: '12px',
                borderRadius: '12px',
                border: '1px solid #e2e8f0',
                boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05)'
            }
        });
    };

    // Event Edit State
    const [editingEventId, setEditingEventId] = useState<string | null>(null);
    const [editEventData, setEditEventData] = useState({
        status: '',
        location: '',
        description: '',
        timestamp: '',
        latitude: '',
        longitude: ''
    });

    const handleEditEventClick = (event: any) => {
        setEditingEventId(event.id);
        setEditEventData({
            status: event.status,
            location: event.location,
            description: event.description || '',
            timestamp: new Date(event.timestamp).toISOString().slice(0, 16),
            latitude: event.latitude || '',
            longitude: event.longitude || ''
        });
    };

    const handleSaveEvent = async (eventId: string) => {
        try {
            const res = await fetch(`/api/shipments/${shipment.id}/event/${eventId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    ...editEventData,
                    timestamp: new Date(editEventData.timestamp + ':00Z').toISOString()
                })
            });

            if (res.ok) {
                setEditingEventId(null);
                router.refresh();
                toast.success("Event updated");
            } else {
                toast.error("Failed to update event");
            }
        } catch (e) {
            console.error(e);
            toast.error("Error updating event");
        }
    };

    // Main Shipment Edit State (existing)
    const [isEditing, setIsEditing] = useState(false);
    
    const parsedSender = parseShipmentInfo(shipment.senderInfo);
    const parsedReceiver = parseShipmentInfo(shipment.receiverInfo);
    
    const [editData, setEditData] = useState({
        createdAt: new Date(shipment.createdAt).toISOString().slice(0, 16),
        origin: shipment.origin || '',
        destination: shipment.destination || '',
        customerEmail: shipment.customerEmail || '',
        productDescription: shipment.productDescription || '',
        imageUrls: shipment.imageUrls || [],
        estimatedDelivery: shipment.estimatedDelivery ? new Date(shipment.estimatedDelivery).toISOString().slice(0, 16) : '',
        senderName: parsedSender.name,
        senderPhone: parsedSender.phone,
        senderAddress: parsedSender.address,
        receiverName: parsedReceiver.name,
        receiverPhone: parsedReceiver.phone,
        receiverAddress: parsedReceiver.address,
    });

    const handleEditSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const res = await fetch(`/api/shipments/${shipment.id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    createdAt: new Date(editData.createdAt + ':00Z').toISOString(),
                    origin: editData.origin,
                    destination: editData.destination,
                    customerEmail: editData.customerEmail,
                    productDescription: editData.productDescription,
                    imageUrls: editData.imageUrls,
                    estimatedDelivery: editData.estimatedDelivery ? new Date(editData.estimatedDelivery + ':00Z').toISOString() : null,
                    senderInfo: JSON.stringify({ name: editData.senderName, phone: editData.senderPhone, address: editData.senderAddress }),
                    receiverInfo: JSON.stringify({ name: editData.receiverName, phone: editData.receiverPhone, address: editData.receiverAddress })
                })
            });
            if (res.ok) {
                setIsEditing(false);
                router.refresh();
                toast.success("Shipment details updated");
            } else {
                toast.error('Failed to update shipment details');
            }
        } catch (e) {
            console.error(e);
            toast.error('Error updating');
        }
    };

    const getStatusStyles = (status: string) => {
        switch (status) {
            case 'CREATED': return 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20';
            case 'PENDING': return 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';
            case 'IN_TRANSIT': return 'bg-blue-500/10 text-blue-400 border-blue-500/20';
            case 'ON_HOLD': return 'bg-orange-500/10 text-orange-500 border-orange-500/20';
            case 'OUT_FOR_DELIVERY': return 'bg-purple-500/10 text-purple-400 border-purple-500/20';
            case 'DELIVERED': return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20';
            case 'RETURNED': return 'bg-red-500/10 text-red-500 border-red-500/20';
            default: return 'bg-slate-800 text-slate-400 border-slate-700';
        }
    };

    const getTimelineDotColor = (status: string) => {
        switch (status) {
            case 'CREATED': return 'bg-yellow-500 border-yellow-500';
            case 'PENDING': return 'bg-indigo-500 border-indigo-500';
            case 'IN_TRANSIT': return 'bg-blue-500 border-blue-500';
            case 'ON_HOLD': return 'bg-orange-500 border-orange-500';
            case 'OUT_FOR_DELIVERY': return 'bg-purple-500 border-purple-500';
            case 'DELIVERED': return 'bg-emerald-500 border-emerald-500';
            case 'RETURNED': return 'bg-red-500 border-red-500';
            default: return 'bg-slate-500 border-slate-500';
        }
    };

    const handleUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        setUpdating(true);
        try {
            const res = await fetch(`/api/shipments/${shipment.id}/event`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    ...formData,
                    timestamp: new Date(formData.timestamp + ':00Z').toISOString()
                })
            });
            if (res.ok) {
                setFormData({
                    status: 'IN_TRANSIT',
                    location: '',
                    description: '',
                    latitude: '',
                    longitude: '',
                    timestamp: new Date().toISOString().slice(0, 16)
                });
                router.refresh();
                toast.success('Status updated successfully');
            } else {
                toast.error('Failed to update');
            }
        } catch (e) {
            console.error(e);
            toast.error('Error updating');
        } finally {
            setUpdating(false);
        }
    };




    return (
        <div className="space-y-6 max-w-[1600px] mx-auto p-6">
            <div className="flex items-center justify-between print:hidden">
                <button
                    onClick={() => router.back()}
                    className="flex items-center text-brand-text-muted hover:text-brand-text transition-colors"
                >
                    <ArrowLeft className="w-5 h-5 mr-2" />
                    Back
                </button>
                <div className="flex gap-3">
                    <PDFDownloadLink
                        document={<ShippingLabelPDF shipment={shipment} settings={settings} />}
                        fileName={`LABEL-${shipment.trackingNumber}.pdf`}
                        className="flex items-center px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all shadow-lg shadow-blue-500/20"
                    >
                        {/* @ts-ignore */}
                        {({ loading }) => (
                            <>
                                <FileText className="w-5 h-5 mr-2" />
                                {loading ? 'Preparing...' : 'Download Label'}
                            </>
                        )}
                    </PDFDownloadLink>
                    <button
                        onClick={() => window.print()}
                        className="flex items-center px-4 py-2 bg-brand-surface hover:bg-brand-border/20 text-brand-text rounded-xl transition-all border border-brand-border"
                    >
                        <Printer className="w-5 h-5 mr-2" />
                        Print Details
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 items-start">
                {/* Left Column: Chat - Sticky */}
                <div className="xl:col-span-3 order-3 xl:order-1 print:hidden">
                    <div className="sticky top-6">
                        <ShipmentChat shipmentId={shipment.id} />
                    </div>
                </div>

                {/* Middle Column: Details & Visual */}
                <div className="xl:col-span-6 space-y-6 order-1 xl:order-2 print:col-span-12 print:w-full">
                    {/* Print Header */}
                    <div className="hidden print:block text-center mb-8">
                        {settings?.logoUrl && <img src={settings.logoUrl} alt="Logo" className="w-32 h-32 object-contain mx-auto mb-4" />}
                        <h1 className="text-4xl font-extrabold text-blue-600 tracking-wider uppercase">{settings?.companyName || 'ATLAS LOGISTICS'}</h1>
                    </div>

                    <div className="bg-brand-surface border border-brand-border rounded-2xl p-8 shadow-xl print:shadow-none print:border-black print:bg-white print:text-black">
                        {/* Header */}
                        <div className="flex justify-between items-start mb-8">
                            <div>
                                <h1 className="text-3xl font-bold text-brand-text print:text-black">{shipment.trackingNumber}</h1>
                                <div className="flex flex-col gap-1 mt-1">
                                    <p className="text-brand-text-muted print:text-gray-600">Created on <FormattedDate date={shipment.createdAt} mode="date" /></p>
                                    {shipment.estimatedDelivery && (
                                        <p className="text-blue-400 print:text-blue-600 font-medium">
                                            Est. Delivery: <FormattedDate date={shipment.estimatedDelivery} mode="date" />
                                        </p>
                                    )}
                                    <button
                                        onClick={() => setIsEditing(!isEditing)}
                                        className="text-xs text-blue-400 hover:text-blue-300 print:hidden"
                                    >
                                        {isEditing ? 'Cancel Edit' : 'Edit Details'}
                                    </button>
                                </div>

                                {isEditing && (
                                    <form onSubmit={handleEditSubmit} className="mt-4 p-4 bg-slate-800/50 rounded-lg border border-slate-700 space-y-3 max-w-md print:hidden">
                                        <div>
                                            <label className="text-xs text-slate-400 block mb-1">Creation Date</label>
                                            <input
                                                type="datetime-local"
                                                className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                value={editData.createdAt}
                                                onChange={e => setEditData({ ...editData, createdAt: e.target.value })}
                                            />
                                        </div>
                                        <div>
                                            <label className="text-xs text-slate-400 block mb-1">Estimated Delivery</label>
                                            <input
                                                type="datetime-local"
                                                className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                value={editData.estimatedDelivery}
                                                onChange={e => setEditData({ ...editData, estimatedDelivery: e.target.value })}
                                            />
                                        </div>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                            {/* Sender Inputs */}
                                            <div className="space-y-3 bg-slate-900/50 p-3 rounded border border-slate-700">
                                                <label className="text-xs font-semibold text-blue-400 uppercase tracking-wider block mb-2">Sender Info</label>
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                    value={editData.senderName}
                                                    onChange={e => setEditData({ ...editData, senderName: e.target.value })}
                                                    placeholder="Sender Name"
                                                />
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                    value={editData.senderPhone}
                                                    onChange={e => setEditData({ ...editData, senderPhone: e.target.value })}
                                                    placeholder="Sender Phone"
                                                />
                                                <textarea
                                                    rows={2}
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white resize-none"
                                                    value={editData.senderAddress}
                                                    onChange={e => setEditData({ ...editData, senderAddress: e.target.value })}
                                                    placeholder="Sender Address"
                                                />
                                            </div>

                                            {/* Receiver Inputs */}
                                            <div className="space-y-3 bg-slate-900/50 p-3 rounded border border-slate-700">
                                                <label className="text-xs font-semibold text-blue-400 uppercase tracking-wider block mb-2">Receiver Info</label>
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                    value={editData.receiverName}
                                                    onChange={e => setEditData({ ...editData, receiverName: e.target.value })}
                                                    placeholder="Receiver Name"
                                                />
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                    value={editData.receiverPhone}
                                                    onChange={e => setEditData({ ...editData, receiverPhone: e.target.value })}
                                                    placeholder="Receiver Phone"
                                                />
                                                <textarea
                                                    rows={2}
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white resize-none"
                                                    value={editData.receiverAddress}
                                                    onChange={e => setEditData({ ...editData, receiverAddress: e.target.value })}
                                                    placeholder="Receiver Address"
                                                />
                                            </div>
                                        </div>
                                        
                                        <div className="grid grid-cols-2 gap-4">
                                            <div>
                                                <label className="text-xs text-brand-text-muted block mb-1">Origin</label>
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                    value={editData.origin}
                                                    onChange={e => setEditData({ ...editData, origin: e.target.value })}
                                                    placeholder="Origin location"
                                                />
                                            </div>
                                            <div>
                                                <label className="text-xs text-slate-400 block mb-1">Destination</label>
                                                <input
                                                    type="text"
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                    value={editData.destination}
                                                    onChange={e => setEditData({ ...editData, destination: e.target.value })}
                                                    placeholder="Destination location"
                                                />
                                            </div>
                                        </div>
                                        <div>
                                            <label className="text-xs text-brand-text-muted block mb-1">Customer Email</label>
                                            <input
                                                type="email"
                                                className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white"
                                                value={editData.customerEmail}
                                                onChange={e => setEditData({ ...editData, customerEmail: e.target.value })}
                                                placeholder="customer@example.com"
                                            />
                                        </div>
                                        <div>
                                            <label className="text-xs text-slate-400 block mb-1">Product Description</label>
                                            <textarea
                                                rows={3}
                                                className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white resize-none"
                                                value={editData.productDescription}
                                                onChange={e => setEditData({ ...editData, productDescription: e.target.value })}
                                                placeholder="Describe the shipment contents..."
                                            />
                                        </div>
                                        <div>
                                            <label className="text-xs text-slate-400 block mb-1">Upload Images</label>
                                            <div className="space-y-3">
                                                <input
                                                    type="file"
                                                    multiple
                                                    accept="image/*"
                                                    onChange={async (e) => {
                                                        if (!e.target.files?.length) {
                                                            return;
                                                        }
                                                        const files = Array.from(e.target.files);

                                                        e.target.value = ''; // Reset input
                                                        const toastId = toast.loading(`Uploading ${files.length} images...`);

                                                        try {
                                                            const uploadPromises = files.map(async (file) => {
                                                                try {
                                                                    const response = await fetch(
                                                                        `/api/upload?filename=${encodeURIComponent(file.name)}`,
                                                                        {
                                                                            method: 'POST',
                                                                            body: file,
                                                                        },
                                                                    );
                                                                    if (!response.ok) {
                                                                        const errorText = await response.text();
                                                                        throw new Error(errorText || response.statusText);
                                                                    }
                                                                    const newBlob = await response.json();
                                                                    return newBlob.url;
                                                                } catch (err) {
                                                                    console.error(`Failed to upload ${file.name}`, err);
                                                                    return null;
                                                                }
                                                            });

                                                            const results = await Promise.all(uploadPromises);
                                                            const successUrls = results.filter((url): url is string => url !== null);

                                                            if (successUrls.length > 0) {
                                                                setEditData(prev => ({
                                                                    ...prev,
                                                                    imageUrls: [...prev.imageUrls, ...successUrls]
                                                                }));
                                                                toast.success(`Successfully uploaded ${successUrls.length} images`, { id: toastId });
                                                            } else {
                                                                // Show the error from the first failed promise if any
                                                                toast.error('Upload failed. Check console for details.', { id: toastId });
                                                            }
                                                        } catch (err: any) {
                                                            console.error(err);
                                                            toast.error(`Error: ${err.message}`, { id: toastId });
                                                        }
                                                    }}
                                                    className="w-full bg-slate-900 border border-slate-700 rounded px-2 py-1 text-sm text-white file:mr-4 file:py-1 file:px-2 file:rounded-md file:border-0 file:text-xs file:font-semibold file:bg-blue-500/10 file:text-blue-500 hover:file:bg-blue-500/20"
                                                />
                                                {/* Preview / Remove List */}
                                                {editData.imageUrls.length > 0 && (
                                                    <div className="grid grid-cols-3 gap-2">
                                                        {editData.imageUrls.map((url: string, i: number) => (
                                                            <div key={i} className="relative group aspect-square bg-slate-900 rounded-md overflow-hidden border border-slate-700">
                                                                {/* eslint-disable-next-line @next/next/no-img-element */}
                                                                <img src={url} alt="preview" className="w-full h-full object-cover" />
                                                                <button
                                                                    type="button"
                                                                    onClick={() => setEditData(prev => ({ ...prev, imageUrls: prev.imageUrls.filter((_: string, idx: number) => idx !== i) }))}
                                                                    className="absolute top-1 right-1 bg-red-500 text-white rounded-full p-0.5 opacity-0 group-hover:opacity-100 transition-opacity"
                                                                >
                                                                    <div className="w-3 h-3 flex items-center justify-center">├ù</div>
                                                                </button>
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                        <div className="flex gap-2">
                                            <button type="submit" className="bg-blue-600 text-white text-xs px-3 py-1 rounded hover:bg-blue-500">Save Changes</button>
                                        </div>
                                    </form>
                                )}
                            </div>
                            <div className={`px-4 py-1.5 rounded-full text-sm font-semibold border ${getStatusStyles(shipment.status)}`}>
                                {shipment.status}
                            </div>
                        </div>

                        {/* Route Info */}
                        <div className="grid grid-cols-2 gap-8 mb-8 pb-8 border-b border-slate-800 print:border-gray-200">
                            <div>
                                <p className="text-brand-text-muted text-sm font-medium uppercase mb-1">From</p>
                                <p className="text-white text-lg font-semibold print:text-black">{shipment.origin}</p>
                                <div className="mt-2 space-y-1">
                                    {parsedSender.name && <p className="text-brand-text font-medium print:text-black">{parsedSender.name}</p>}
                                    {parsedSender.phone && <p className="text-brand-text-muted text-sm print:text-gray-600">{parsedSender.phone}</p>}
                                    {parsedSender.address && <p className="text-brand-text-muted text-sm print:text-gray-600">{parsedSender.address}</p>}
                                </div>
                            </div>
                            <div className="text-right">
                                <p className="text-slate-500 text-sm font-medium uppercase mb-1">To</p>
                                <p className="text-white text-lg font-semibold print:text-black">{shipment.destination}</p>
                                <div className="mt-2 space-y-1 flex flex-col items-end">
                                    {parsedReceiver.name && <p className="text-brand-text font-medium print:text-black">{parsedReceiver.name}</p>}
                                    {parsedReceiver.phone && <p className="text-brand-text-muted text-sm print:text-gray-600">{parsedReceiver.phone}</p>}
                                    {parsedReceiver.address && <p className="text-brand-text-muted text-sm print:text-gray-600">{parsedReceiver.address}</p>}
                                </div>
                            </div>
                        </div>

                        {/* Product Details */}
                        {(shipment.productDescription || (shipment.imageUrls && shipment.imageUrls.length > 0)) && (
                            <div className="mb-8 pb-8 border-b border-slate-800 print:border-gray-200">
                                <h3 className="text-white font-semibold mb-4 print:text-black">Product Details</h3>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    {shipment.productDescription && (
                                        <div>
