import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/prisma";
import { NextResponse } from "next/server";
import { sendChatNotification } from "@/lib/email";

export async function GET(req: Request, { params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    // Public endpoint for tracking page (fetching messages for a shipment)
    // In a real app, you might want to protect this with a token, but for now it's public if you know the ID/Tracking Number.
    // However, the ID (UUID) is hard to guess.

    try {
        const messages = await (prisma as any).message.findMany({
            where: { shipmentId: id },
            orderBy: { createdAt: 'asc' }
        });
        return NextResponse.json(messages);
    } catch (e) {
        return new NextResponse("Error fetching messages", { status: 500 });
    }
}

export async function POST(req: Request, { params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const session = await getServerSession(authOptions);

    try {
        const { content, sender, imageUrl } = await req.json();

        // Validation
        if (!content && !imageUrl) return new NextResponse("Content or Image required", { status: 400 });

        // Determine role:
        // If session exists and user is admin/super_admin, they can be "ADMIN".
        // Otherwise, it's a "CLIENT".

        const actualSender = sender === 'CLIENT' ? 'CLIENT' : 'ADMIN';

        // If trying to send as ADMIN, verify they actually have an admin session
        if (actualSender === 'ADMIN') {
            if (!session || (session.user.role !== 'ADMIN' && session.user.role !== 'SUPER_ADMIN')) {
                return new NextResponse("Unauthorized", { status: 401 });
            }
        }

        const message = await (prisma as any).message.create({
            data: {
                content: content || "",
                imageUrl: imageUrl || null,
                sender: actualSender,
                shipmentId: id
            }
        });

        // Fire email notification synchronously to prevent Next.js from aggressively killing the background worker
        try {
            const shipment = await (prisma as any).shipment.findUnique({
                where: { id },
                include: { admin: true }
            });

            if (shipment) {
                if (actualSender === 'ADMIN') {
                    // Admin replied. Notify Customer if email exists.
                    if (shipment.customerEmail) {
                        await sendChatNotification(
                            shipment.customerEmail, 
                            shipment.trackingNumber, 
                            shipment.id, 
                            content || "[Image attachment]", 
                            false
                        );
                    }
                } else {
                    // Customer replied. Notify Admin.
                    if (shipment.admin && shipment.admin.email) {
                        await sendChatNotification(
                            shipment.admin.email, 
                            shipment.trackingNumber, 
                            shipment.id, 
                            content || "[Image attachment]", 
                            true
                        );
                    }
                }
            }
        } catch (err) {
            console.error("Background chat email error:", err);
        }

        return NextResponse.json(message);
    } catch (e) {
        console.error(e);
        return new NextResponse("Error sending message", { status: 500 });
    }
}

import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/prisma";
import { NextResponse } from "next/server";

import { logAction } from "@/lib/logger";

export async function PATCH(req: Request, { params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const session = await getServerSession(authOptions);
    if (!session) return new NextResponse("Unauthorized", { status: 401 });

    try {
        const body = await req.json();

        // Allowed fields to update
        const { createdAt, status, origin, destination, trackingNumber, productDescription, imageUrls, senderInfo, receiverInfo, customerEmail } = body;

        // Verify ownership
        const existingShipment = await prisma.shipment.findUnique({ where: { id } });
        if (!existingShipment || (existingShipment.adminId !== session.user.id && session.user.role !== 'SUPER_ADMIN')) {
            return new NextResponse("Unauthorized", { status: 401 });
        }

        const updateData: any = {};
        if (createdAt) updateData.createdAt = new Date(createdAt);
        if (status) updateData.status = status;
        if (origin) updateData.origin = origin;
        if (destination) updateData.destination = destination;
        if (trackingNumber) updateData.trackingNumber = trackingNumber;
        if (productDescription !== undefined) updateData.productDescription = productDescription;
        if (imageUrls !== undefined) updateData.imageUrls = JSON.stringify(imageUrls); // SQLite fix
        if (body.estimatedDelivery !== undefined) updateData.estimatedDelivery = body.estimatedDelivery ? new Date(body.estimatedDelivery) : null;
        if (senderInfo !== undefined) updateData.senderInfo = senderInfo;
        if (receiverInfo !== undefined) updateData.receiverInfo = receiverInfo;
        if (customerEmail !== undefined) updateData.customerEmail = customerEmail;

        const updatedShipment = await prisma.shipment.update({
            where: { id },
            data: updateData
        });

        await logAction(session.user.id, "UPDATE_SHIPMENT", id, updateData);

        const parsedShipment = {
            ...updatedShipment,
            imageUrls: updatedShipment.imageUrls ? JSON.parse(updatedShipment.imageUrls) : []
        };

        return NextResponse.json(parsedShipment);
    } catch (err) {
        console.error("Error updating shipment:", err);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
    const { id } = await params;
    const session = await getServerSession(authOptions);
    if (!session) return new NextResponse("Unauthorized", { status: 401 });

    try {
        // Verify ownership
        const existingShipment = await prisma.shipment.findUnique({ where: { id } });
        if (!existingShipment || (existingShipment.adminId !== session.user.id && session.user.role !== 'SUPER_ADMIN')) {
            return new NextResponse("Unauthorized", { status: 401 });
        }

        // Soft Delete
        await prisma.shipment.update({
            where: { id },
            data: {
                isDeleted: true,
                deletedAt: new Date()
            }
        });

        await logAction(session.user.id, "TRASH_SHIPMENT", id, { trackingNumber: existingShipment.trackingNumber });

        return new NextResponse(null, { status: 204 });
    } catch (err) {
        console.error("Error trashing shipment:", err);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/prisma";
import { NextResponse } from "next/server";
import { sendShipmentEmail } from "@/lib/email";
import { logAction } from "@/lib/logger";
import { parseShipmentInfo } from "@/lib/utils";
import React from 'react';
import { renderToBuffer } from '@react-pdf/renderer';
import ShipmentDetailsPDF from '@/components/pdf/ShipmentDetailsPDF';

export async function POST(req: Request) {
    const session = await getServerSession(authOptions);
    if (!session) {
        return new NextResponse("Unauthorized", { status: 401 });
    }

    try {
        const body = await req.json();
        const { senderInfo, receiverInfo, origin, destination, estimatedDelivery, customerEmail } = body;

        // Generate random tracking number (e.g., TRK12345678)
        const trackingNumber = `TRK${Math.floor(10000000 + Math.random() * 90000000)}`;

        const shipment = await prisma.shipment.create({
            data: {
                trackingNumber,
                senderInfo,
                receiverInfo,
                origin,
                destination,
                customerEmail,
                estimatedDelivery: estimatedDelivery ? new Date(estimatedDelivery) : null,
                imageUrls: JSON.stringify(body.imageUrls || []), // SQLite fix
                createdAt: body.createdAt ? new Date(body.createdAt) : undefined,
                productDescription: body.productDescription,
                status: "CREATED",
                adminId: session.user.id,
                events: {
                    create: {
                        status: "CREATED",
                        location: origin || "System",
                        description: "Shipment created",
                        timestamp: body.createdAt ? new Date(body.createdAt) : undefined
                    }
                }
            }
        });

        // Log action
        await logAction(session.user.id, "CREATE_SHIPMENT", shipment.id, { trackingNumber });

        // Send Email
        if (customerEmail) {
            const sender = parseShipmentInfo(senderInfo);
            const receiver = parseShipmentInfo(receiverInfo);

            const settings = await prisma.siteSettings.findUnique({ where: { id: "default" } });

            let pdfBuffer;
            try {
                pdfBuffer = await renderToBuffer(React.createElement(ShipmentDetailsPDF, { shipment, settings }) as any);
            } catch (err) {
                console.error("Failed to generate PDF label", err);
            }

            // Must await in serverless/Vercel to avoid early termination
            await sendShipmentEmail({
                to: customerEmail,
                trackingNumber,
                status: "CREATED",
                location: origin || "System",
                receiverName: receiver.name,
                receiverAddress: receiver.address,
                senderName: sender.name,
                origin,
                destination,
                estimatedDelivery: estimatedDelivery ? new Date(estimatedDelivery).toLocaleDateString() : undefined,
                productDescription: body.productDescription,
                attachment: pdfBuffer ? {
                    filename: `Label-${trackingNumber}.pdf`,
                    content: pdfBuffer
                } : undefined
            });
        }

        return NextResponse.json(shipment);
    } catch (error) {
        console.error("[SHIPMENTS_POST]", error);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

export async function GET(req: Request) {
    const session = await getServerSession(authOptions);
    if (!session) {
        return new NextResponse("Unauthorized", { status: 401 });
    }

    try {
        const { searchParams } = new URL(req.url);
        const viewAs = searchParams.get('viewAs');

        // Only enforce adminId if the user is NOT a SUPER_ADMIN,
        // OR if they are a SUPER_ADMIN requesting to view a specific admin.
        // If a SUPER_ADMIN requests without viewAs, they get all shipments.
        const whereClause: any = { isDeleted: false };
        if (session.user.role === 'SUPER_ADMIN' && viewAs) {
            whereClause.adminId = viewAs;
        } else if (session.user.role !== 'SUPER_ADMIN') {
            whereClause.adminId = session.user.id;
        }

        const shipments = await prisma.shipment.findMany({
            where: whereClause,
            orderBy: {
                createdAt: 'desc'
            },
            include: {
                events: {
                    orderBy: [
                        { timestamp: 'desc' },
                        { createdAt: 'desc' }
                    ],
                    take: 1
                }
            }
        });

        const parsedShipments = shipments.map(s => {
            let parsedImageUrls = [];
            try {
                parsedImageUrls = s.imageUrls ? JSON.parse(s.imageUrls) : [];
            } catch (e) {
                console.error("Failed to parse imageUrls for shipment", s.id, e);
            }
            return {
                ...s,
                imageUrls: parsedImageUrls
            };
        });

        return NextResponse.json(parsedShipments);
    } catch (error) {
        console.error("[SHIPMENTS_GET]", error);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

