import TrackingChat from "@/components/TrackingChat";
import FormattedDate from "@/components/FormattedDate";
import { parseShipmentInfo } from '@/lib/utils';

async function getShipment(trackingNumber: string) {
    // Normalize: uppercase and remove hyphens
    const normalizedTracking = trackingNumber.toUpperCase().replace(/-/g, '');

    // Existing records in DB might have 'TRK-' or 'TRK'. We construct both to guarantee a match.
    // e.g. TRK12345 -> 'TRK12345' (new) or 'TRK-12345' (legacy)
    const legacyTracking = normalizedTracking.startsWith('TRK') ? normalizedTracking.replace('TRK', 'TRK-') : normalizedTracking;

    const shipment = await prisma.shipment.findFirst({
        where: {
            OR: [
                { trackingNumber: normalizedTracking },
                { trackingNumber: legacyTracking }
            ],
            isDeleted: false
        },
        include: {
            admin: {
                select: { name: true, email: true } // Only expose needed public info
            },
            events: {
                orderBy: [
                    { timestamp: 'desc' },
                    { createdAt: 'desc' }
                ]
            }
        }
    });

    if (!shipment) return null;

    let parsedImageUrls = [];
    try {
        const rawUrl = (shipment as any).imageUrls;
        parsedImageUrls = rawUrl ? JSON.parse(rawUrl) : [];
        if (!Array.isArray(parsedImageUrls)) parsedImageUrls = [];
    } catch (e) {
        console.error("Failed to parse imageUrls", e);
        parsedImageUrls = [];
    }

    // Sort events: latest by timestamp/createdAt first, but "CREATED" always last
    const sortedEvents = [...shipment.events].sort((a, b) => {
        if (a.status === 'CREATED' && b.status !== 'CREATED') return 1;
        if (a.status !== 'CREATED' && b.status === 'CREATED') return -1;
        
        const timeA = new Date(a.timestamp).getTime();
        const timeB = new Date(b.timestamp).getTime();
        if (timeB !== timeA) return timeB - timeA;
        
        const createdA = new Date(a.createdAt).getTime();
        const createdB = new Date(b.createdAt).getTime();
        return createdB - createdA;
    });

    return {
        ...shipment,
        events: sortedEvents,
        imageUrls: parsedImageUrls,
        parsedSender: parseShipmentInfo(shipment.senderInfo),
        parsedReceiver: parseShipmentInfo(shipment.receiverInfo)
    };
}

function getStatusProgress(status: string) {
    switch (status) {
        case 'CREATED': return 10;
        case 'PENDING': return 10;
        case 'ON_HOLD': return 30;
        case 'IN_TRANSIT': return 50;
        case 'OUT_FOR_DELIVERY': return 80;
        case 'DELIVERED': return 100;
        case 'RETURNED': return 100;
        default: return 0;
    }
}

function getStatusColor(status: string) {
    switch (status) {
        case 'CREATED': return 'text-yellow-500';
        case 'PENDING': return 'text-indigo-500';
        case 'IN_TRANSIT': return 'text-blue-400';
        case 'ON_HOLD': return 'text-orange-500';
        case 'OUT_FOR_DELIVERY': return 'text-purple-400';
        case 'OUT_FOR_DELIVERY': return 'text-purple-400';
        case 'DELIVERED': return 'text-emerald-400';
        case 'RETURNED': return 'text-red-500';
        default: return 'text-slate-400';
    }
}

function getTimelineDotColor(status: string) {
    switch (status) {
        case 'CREATED': return 'bg-yellow-500 shadow-[0_0_0_4px_rgba(234,179,8,0.2)]';
        case 'PENDING': return 'bg-indigo-500 shadow-[0_0_0_4px_rgba(99,102,241,0.2)]';
        case 'IN_TRANSIT': return 'bg-blue-500 shadow-[0_0_0_4px_rgba(59,130,246,0.2)]';
        case 'ON_HOLD': return 'bg-orange-500 shadow-[0_0_0_4px_rgba(249,115,22,0.2)]';
        case 'OUT_FOR_DELIVERY': return 'bg-purple-500 shadow-[0_0_0_4px_rgba(168,85,247,0.2)]';
        case 'OUT_FOR_DELIVERY': return 'bg-purple-500 shadow-[0_0_0_4px_rgba(168,85,247,0.2)]';
        case 'DELIVERED': return 'bg-emerald-500 shadow-[0_0_0_4px_rgba(16,185,129,0.2)]';
        case 'RETURNED': return 'bg-red-500 shadow-[0_0_0_4px_rgba(239,68,68,0.2)]';
        default: return 'bg-slate-500 shadow-[0_0_0_4px_rgba(100,116,139,0.2)]';
    }
}

